// Collect items from all branches (GitHub, Redmine, Slack)
// Also loads previous standup from static workflow data for memory context
const allItems = $input.all().map(i => i.json);

const commits = [];
const issues = [];
const messages = [];

for (const it of allItems) {
  // GitHub commit shape: { sha, commit: { message }, html_url, ... }
  if (it.sha && it.commit) {
    const msg = (it.commit.message || '').split('\n')[0].trim();
    const sha = String(it.sha).slice(0, 7);
    commits.push(`${sha}: ${msg}`);
  }
  // Redmine issues list shape: { issues: [...] }
  if (Array.isArray(it.issues)) {
    for (const iss of it.issues) {
      issues.push(`#${iss.id} [${iss.status?.name || 'open'}] ${iss.subject}`);
    }
  }
  // Slack message shape: { type: 'message', text: '...' }
  if (it.type === 'message' && it.text) {
    const txt = it.text.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
    if (txt.length > 0) messages.push(txt.slice(0, 200));
  }
}

const dedupe = (arr) => [...new Set(arr)].filter(Boolean);

const today = new Date().toISOString().split('T')[0];

const activity = [
  `## GitHub commits (${today}, last 24h)`,
  ...(dedupe(commits).length ? dedupe(commits).map(c => `- ${c}`) : ['- (no commits in last 24h)']),
  '',
  `## Redmine issues (assigned to me, open)`,
  ...(dedupe(issues).length ? dedupe(issues).map(c => `- ${c}`) : ['- (no open issues assigned)']),
  '',
  `## Recent Slack messages`,
  ...(dedupe(messages).length ? dedupe(messages).slice(0, 10).map(c => `- ${c}`) : ['- (no messages found)']),
].join('\n');

// Load previous standup from N8N static workflow data (Window Buffer Memory equivalent)
const staticData = $getWorkflowStaticData('global');
const previousStandup = staticData.lastStandup || null;
const previousDate = staticData.lastStandupDate || null;

return [{ json: { activity, today, previousStandup, previousDate } }];

// Save current standup to static workflow data (memory persistence)
const claudeOutput = $input.first().json;
const codeOutput = $('Code: Merge & Format Activity').first().json;

const staticData = $getWorkflowStaticData('global');
staticData.lastStandup = claudeOutput.output || '';
staticData.lastStandupDate = codeOutput.today || new Date().toISOString().split('T')[0];

// Pass through Claude output unchanged
return [$input.first()];
